function safeDecode(s) {
  // Keep it predictable: if decode fails, return the raw string
  try {
    return decodeURIComponent(s);
  } catch {
    return s;
  }
}

export default function parseQueryString(qs) {
  if (typeof qs !== 'string') return {};

  const raw = qs.startsWith('?') ? qs.slice(1) : qs;
  if (!raw) return {};

  const out = {};

  for (const part of raw.split('&')) {
    if (!part) continue;

    const eq = part.indexOf('=');
    const kRaw = eq === -1 ? part : part.slice(0, eq);
    const vRaw = eq === -1 ? '' : part.slice(eq + 1);

    const k = safeDecode(kRaw.replace(/\+/g, ' ')).trim();
    if (!k) continue;

    const v = safeDecode(vRaw.replace(/\+/g, ' '));
    out[k] = v;
  }

  return out;
}
